import "./App.css";
/** Tạo component Feature bằng arrow function */
const Feature = () => {
  return (
    <div className="feature">
      <img src="" alt="Feature" className="feature-image" />
      <h3 className="feature-title">Feature Title</h3>
      <p className="feature-desc">
        Lorem ipsum dolor sit amet consectetur adipisicing elit. Recusandae
        quaerat distinctio illum inventore, doloremque corporis? Voluptatum
        maxime dignissimos incidunt, eveniet omnis quam, culpa dolorum
        repellendus, explicabo ipsam in natus suscipit.
      </p>
    </div>
  );
};
/** End Feature */

/**
 *
 * App <=> parent component
 * Feature <=> child component
 *
 * App có thể chứa nhiều Feature, nhưng Feature không thể chứa App
 */

/** Component YoutubeItem */
const YoutubeItem = () => {
  return (
    <div className="youtube-item">
      <img
        src="https://images.unsplash.com/photo-1768487422639-7ba3900d0f02"
        alt="ảnh-1"
      />
    </div>
  );
};
/** End YoutubeItem */

/**
 * App <=> parent component
 * Feature <=> child component
 * YoutubeItem <=> child component
 * */

const App = () => {
  return (
    <>
      <Feature />
      <Feature />
      <Feature />
      <YoutubeItem />
    </>
  );
};

export default App;
